export async function loadLocaleMessages(locale: string): Promise<AnyObj> {
  const fns = loaders[locale] ?? [];
  const parts = await Promise.all(fns.map((fn) => fn()));
  return parts.reduce((acc, part) => deepMerge(acc, part), {} as AnyObj);
}

